function solve(n, edges, label) {
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 0;

    function isPalindrome(s) {
        let left = 0, right = s.length - 1;
        while (left < right) {
            if (s[left] !== s[right]) return false;
            left++;
            right--;
        }
        return true;
    }

    function dfs(node, visited, path) {
        if (isPalindrome(path)) {
            maxLen = Math.max(maxLen, path.length);
        }
        for (const neighbor of adj[node]) {
            if (!(visited & (1 << neighbor))) {
                const newVisited = visited | (1 << neighbor);
                const newPath = path + label[neighbor];
                dfs(neighbor, newVisited, newPath);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        const initialVisited = 1 << i;
        const initialPath = label[i];
        dfs(i, initialVisited, initialPath);
    }

    return maxLen;
}
